worker.on("exit", (code) => {
  _terminated = true;
  if (readyTimer) clearTimeout(readyTimer);
  if (!isResolved) {
    isResolved = true;
    reject(new Error(`[jxl-worker-node] Worker exited with code ${code} before ready`));
    return;
  }
  if (code !== 0) {
    for (const h of messageHandlers.slice()) {
      h({
        type: "worker_error",
        code: "WorkerCrashed",
        message: `[jxl-worker-node] worker exited with code ${code}`,
      });
    }
    for (const h of messageHandlers.slice()) {
      h({
        type: "worker_shutdown_ack",
      });
    }
  }
});

private checkBudget(): boolean {
  if (this.opts.budgetMs == null) return false;
  return performance.now() - this.stageStartMs > this.opts.budgetMs;
}

function isLoadedBinding(value: unknown, onDiagnostic?: (msg: string) => void): value is CodecModule {
  if (!isRecord(value)) {
    onDiagnostic?.("Binding is not a record");
    return false;
  }
  if (typeof value["probe"] === "function") {
    try {
      const probe = value["probe"]();
